/// <reference path="./online-streaming-provider.d.ts" />

class Provider {
    baseUrl = "https://anineko.to"

    getSettings(): Settings {
        return {
            episodeServers: ["HD-1", "HD-2", "HD-1 (HardSub)", "HD-2 (HardSub)"],
            supportsDub: true,
        }
    }

    async search(query: SearchOptions): Promise<SearchResult[]> {
        const response = await fetch(`${this.baseUrl}/ajax/search?q=${encodeURIComponent(query.query)}`)

        const json = await response.json()

        const results = json?.results

        return results.map((item: any) => ({
            id: `${item.url}:${query.dub ? "dub" : "sub"}`,
            title: item.title,
            url: this.baseUrl + item.url,
            subOrDub: query.dub ? "dub" : "sub",
        }))
    }

    async findEpisodes(Id: string): Promise<EpisodeDetails[]> {
        const [id, lang] = Id.split(":")
        const response = await fetch(this.baseUrl + id)

        const html = await response.text()
        const $ = LoadDoc(html)

        const episodes: EpisodeDetails[] = []

        $(".nv-info-episode-grid article.nv-info-episode-item").each((i, element) => {
            const mainAnchor = element.children("a.nv-info-episode-main")
            const relativeUrl = mainAnchor.attr("href")

            const titleText = mainAnchor.children("strong").text().trim()

            const epNumberMatch = relativeUrl.match(/ep-(\d+)/)
            const epNumberStr = epNumberMatch ? epNumberMatch[1] : (i + 1).toString()

            episodes.push({
                id: lang, 
                number: parseInt(epNumberStr, 10) || (i + 1),
                url: this.baseUrl + relativeUrl,
                title: titleText || `Episode ${epNumberStr}`
            })
        })

        return episodes
    }

    async findEpisodeServer(episode: EpisodeDetails, _server: string): Promise<EpisodeServer> {
        if (episode.id === "dub" && _server.includes("(HardSub)")) {
            return
        }

        const response = await fetch(episode.url)
        const html = await response.text()
        const $ = LoadDoc(html)

        let targetGroupId = "sub"
        if (episode.id === "dub") {
            targetGroupId = "dub"
        } else if (_server.includes("(HardSub)")) {
            targetGroupId = "hsub"
        }

        const cleanedServerName = _server.replace(/\s*\(HardSub\)/i, "").trim()

        let rawVideoUrl: string | undefined

        $(`.lang-group[data-id="${targetGroupId}"] button.server-video`).each((i, element) => {
            const buttonText = element.text().trim();
            if (buttonText.includes(cleanedServerName)) {
                rawVideoUrl = element.attr("data-video")
            }
        })

        const idMatch = rawVideoUrl.match(/vibeplayer\.site\/([^?]+)/)
        const videoId = idMatch ? idMatch[1] : ""

        const embedRes = await fetch(rawVideoUrl)
        const embedHtml = await embedRes.text()

        const srcMatch = embedHtml.match(/const\s+src\s*=\s*["']([^"']+)["']/);
        const finalUrl = srcMatch ? srcMatch[1] : "";

        const subtitles: any[] = []

        if ((targetGroupId === "sub" || targetGroupId === "dub") && rawVideoUrl.includes("?sub=") && !_server.includes("(HardSub)")) {
            const subUrlMatch = rawVideoUrl.match(/\?sub=([^&]+)/)
            if (subUrlMatch) {
                subtitles.push({
                    id: "eng",
                    url: decodeURIComponent(subUrlMatch[1]),
                    language: "English"
                })
            }
        }

        return {
            server: _server,
            headers: {
                "Referer": `https://vibeplayer.site/${videoId}`
            },
            videoSources: [
                {
                    url: finalUrl,
                    type: "m3u8",
                    quality: "auto",
                    subtitles: subtitles
                }
            ]
        }
    }
}
